import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import styles from './AiPage.module.css'; // 假设已创建

const AiPage = () => {
  const { id } = useParams();
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  // 系统提示配置
  const systemPrompts = {
    1: "You are a cybersecurity expert teaching password security...",
    // ...其他课程提示
  };

  // 初始化聊天
  useEffect(() => {
    const welcomeMessages = {
      1: "Hi! I'm your Password Security Assistant...",
      // ...其他欢迎消息
    };
    
    const saved = localStorage.getItem(`chatMessages_${id}`);
    setMessages(saved ? JSON.parse(saved) : [
      { role: 'assistant', content: welcomeMessages[id] || "Hello! How can I help?" }
    ]);
  }, [id]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage = { role: 'user', content: input };
    const newMessages = [...messages, userMessage];
    setMessages(newMessages);
    setInput('');
    setIsLoading(true);
    setError(null);

    try {
      const response = await fetchBailianResponse(input, systemPrompts[id]);
      setMessages([...newMessages, { role: 'assistant', content: response }]);
    } catch (err) {
      setError(err.message);
      setMessages([...newMessages, { 
        role: 'assistant', 
        content: "⚠️ Failed to get response: " + err.message 
      }]);
    } finally {
      setIsLoading(false);
    }
  };

  // 真实 API 调用函数
  const fetchBailianResponse = async (userInput, systemPrompt) => {
    const response = await fetch('https://dashscope.aliyun.com/api/v1/...', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${process.env.REACT_APP_DASHSCOPE_API_KEY}`
      },
      body: JSON.stringify({
        model: "qwen-turbo",
        input: { messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userInput }
        ]}
      })
    });

    if (!response.ok) throw new Error(`API Error: ${response.status}`);
    const data = await response.json();
    return data.output.text;
  };

  return (
    <div className={styles.container}>
      {/* 优化后的 UI 结构 */}
      {error && <div className={styles.errorBanner}>{error}</div>}
      {/* ...其他 JSX */}
    </div>
  );
};

export default AiPage;
